+    if (!isFocused) {
+      player.pause();
+      setShowPlayer(false);
+    }
+  }, [isFocused, player]);
+
+  useEffect(() => () => player.pause(), [player]);
+
+  const handlePlay = () => {
+    setShowPlayer(true);
+    player.play();
+  };
+
+  return (
+    <View style={styles.card}>
+      <View style={styles.frame}>
+        {showPlayer ? (
+          <VideoView
+            player={player}
+            nativeControls
+            allowsFullscreen
+            contentFit="cover"
+            style={styles.video}
+          />
+        ) : (
