import { useEffect, useState } from 'react';
import { Image, Pressable, StyleSheet, Text, View } from 'react-native';
import { useIsFocused } from '@react-navigation/native';
import { useVideoPlayer, VideoView } from 'expo-video';

import { ExampleVideo } from '@/features/campaigns/types';

interface ExampleVideoCardProps {
  video: ExampleVideo;
}

export function ExampleVideoCard({ video }: ExampleVideoCardProps) {
  const isFocused = useIsFocused();
  const [showPlayer, setShowPlayer] = useState(false);
  const player = useVideoPlayer(video.videoUrl, (instance) => {
    instance.loop = false;
    instance.muted = false;
  });

  useEffect(() => {
    if (!isFocused) {
      player.pause();
      setShowPlayer(false);
    }
  }, [isFocused, player]);

  useEffect(() => () => player.pause(), [player]);

  const handlePlay = () => {
    setShowPlayer(true);
    player.play();
  };

  return (
    <View style={styles.card}>
      <View style={styles.frame}>
        {showPlayer ? (
          <VideoView
            player={player}
            nativeControls
            allowsFullscreen
            contentFit="cover"
            style={styles.video}
          />
        ) : (
          <Pressable onPress={handlePlay} style={styles.posterButton}>
            <Image source={{ uri: video.posterUrl }} style={styles.video} />
            <View style={styles.overlay}>
              <View style={styles.playButton}>
                <Text style={styles.playLabel}>Play</Text>
              </View>
            </View>
          </Pressable>
        )}
      </View>
      <Text style={styles.title}>{video.title}</Text>
      <Text style={styles.meta}>
        {video.libraryName} • {video.durationLabel} • {video.creatorLabel}
      </Text>
    </View>
  );
}

