    color: '#111827',
  },
  title: {
    fontSize: 15,
    fontWeight: '600',
    color: '#111827',
  },
  meta: {
    fontSize: 13,
    color: '#6b7280',
  },
});

import FontAwesome from '@expo/vector-icons/FontAwesome';
