  const [start, end] = getPalette(brandName);

  return (
    <LinearGradient colors={[start, end]} style={[styles.logo, { width: size, height: size }]}>
      <Text style={[styles.initials, { fontSize: Math.max(12, size * 0.34) }]}>
        {getInitials(brandName)}
      </Text>
    </LinearGradient>
  );
}

