import { StyleSheet, Text } from 'react-native';

const palettes = [
  ['#007AFF', '#5AA9FF'],
  ['#2A7FFF', '#8BB7FF'],
  ['#4B88FF', '#CAD6FF'],
  ['#005FE0', '#78A9FF'],
];

interface BrandLogoProps {
  brandName: string;
  size?: number;
}

const getInitials = (brandName: string) =>
  brandName
    .split(' ')
    .map((part) => part[0])
    .join('')
    .slice(0, 2)
    .toUpperCase();

const getPalette = (brandName: string) =>
  palettes[
    brandName.split('').reduce((sum, char) => sum + char.charCodeAt(0), 0) % palettes.length
  ];

export function BrandLogo({ brandName, size = 40 }: BrandLogoProps) {
  const [start, end] = getPalette(brandName);

  return (
    <LinearGradient colors={[start, end]} style={[styles.logo, { width: size, height: size }]}>
      <Text style={[styles.initials, { fontSize: Math.max(12, size * 0.34) }]}>
        {getInitials(brandName)}
      </Text>
    </LinearGradient>
  );
}

const styles = StyleSheet.create({
  logo: {
    alignItems: 'center',
    justifyContent: 'center',
    borderRadius: 8,
  },
  initials: {
    color: '#ffffff',
    fontWeight: '700',
    letterSpacing: 0,
  },
});

import { useMemo } from 'react';
import { Stack } from 'expo-router';
import { StyleSheet, Text, View } from 'react-native';

import { AppScreen } from '@/components/AppScreen';
import { EmptyState } from '@/components/EmptyState';
import { SubmissionRow } from '@/features/campaigns/components/SubmissionRow';
import { useCreatorFlowStore } from '@/store/creatorFlowStore';

export default function SubmissionsScreen() {
  const campaigns = useCreatorFlowStore((state) => state.campaigns);
  const submissions = useCreatorFlowStore((state) => state.submissions);
  const brandLookup = useMemo(
    () => Object.fromEntries(campaigns.map((campaign) => [campaign.id, campaign.brandName])),
    [campaigns]
  );

  return (
    <AppScreen scroll contentContainerStyle={styles.content}>
      <Stack.Screen options={{ title: 'Submissions' }} />
      <View style={styles.header}>
        <Text style={styles.title}>Submission status</Text>
        <Text style={styles.subtitle}>Track every pending, approved, and rejected video.</Text>
      </View>
      {submissions.length ? (
        submissions.map((submission) => (
          <SubmissionRow
            key={submission.id}
            submission={submission}
            brandName={brandLookup[submission.campaignId] ?? 'Unknown campaign'}
          />
        ))
      ) : (
        <EmptyState
          title="No submissions yet"
          message="Submit a TikTok or Instagram URL from any campaign to see it here."
        />
      )}
    </AppScreen>
  );
}

const styles = StyleSheet.create({
  content: {
    gap: 12,
  },
  header: {
    gap: 6,
    marginBottom: 4,
  },
  title: {
    fontSize: 28,
    fontWeight: '700',
    color: '#111827',
  },
  subtitle: {
    fontSize: 14,
    lineHeight: 20,
    color: '#6b7280',
  },
});

export type SubmissionStatus = 'pending' | 'approved' | 'rejected';

export type Platform = 'tiktok' | 'instagram';

export interface ExampleVideo {
  id: string;
  title: string;
  libraryName: string;
  videoUrl: string;
  posterUrl: string;
  durationLabel: string;
  creatorLabel: string;
}

export interface Campaign {
  id: string;
  brandName: string;
  headline: string;
  payoutUsd: number;
  deadlineIso: string;
  brief: string;
  requirements: string[];
  exampleVideoIds: string[];
}

export interface Submission {
  id: string;
  campaignId: string;
  platform: Platform;
  creatorUrl: string;
  status: SubmissionStatus;
  submittedAtIso: string;
}

import { Stack, useLocalSearchParams, useRouter } from 'expo-router';
import { StyleSheet, Text, View } from 'react-native';

import { Button } from '@/components/Button';
import { AppScreen } from '@/components/AppScreen';
import { EmptyState } from '@/components/EmptyState';
import { SymbolIcon } from '@/components/SymbolIcon';
import { BrandLogo } from '@/features/campaigns/components/BrandLogo';
import { ExampleVideoCard } from '@/features/campaigns/components/ExampleVideoCard';
import { formatCurrency, formatDate } from '@/features/campaigns/utils/formatters';
import { useCreatorFlowStore } from '@/store/creatorFlowStore';

export default function CampaignDetailScreen() {
  const router = useRouter();
  const { id } = useLocalSearchParams<{ id: string }>();
  const campaign = useCreatorFlowStore((state) => state.getCampaign(id));
  const videos = useCreatorFlowStore((state) =>
    campaign ? state.getCampaignVideos(campaign) : []
  );

  if (!campaign) {
    return (
      <AppScreen contentContainerStyle={styles.emptyScreen}>
        <Stack.Screen options={{ title: 'Campaign' }} />
        <EmptyState title="Campaign not found" message="Pick another campaign from the list." />
      </AppScreen>
    );
  }

  return (
    <AppScreen scroll contentContainerStyle={styles.content}>
      <Stack.Screen options={{ title: campaign.brandName }} />
      <View style={styles.hero}>
        <View style={styles.brandRow}>
          <BrandLogo brandName={campaign.brandName} size={48} />
          <Text style={styles.brand}>{campaign.brandName}</Text>
        </View>
        <Text style={styles.headline}>{campaign.headline}</Text>
        <View style={styles.metaGroup}>
          <Text style={styles.meta}>{formatCurrency(campaign.payoutUsd)} per video</Text>
          <View style={styles.deadlineRow}>
            <SymbolIcon name="calendar" fallback="calendar" size={14} color="#6b7280" />
            <Text style={styles.meta}>Deadline {formatDate(campaign.deadlineIso)}</Text>
          </View>
        </View>
      </View>
      <View style={styles.section}>
        <Text style={styles.sectionTitle}>Brief</Text>
        <Text style={styles.body}>{campaign.brief}</Text>
      </View>
      <View style={styles.section}>
        <Text style={styles.sectionTitle}>Requirements</Text>
        {campaign.requirements.map((item) => (
          <Text key={item} style={styles.bullet}>
            • {item}
          </Text>
        ))}
      </View>
      <View style={styles.section}>
        <Text style={styles.sectionTitle}>Example videos</Text>
        {videos.map((video) => (
          <ExampleVideoCard key={video.id} video={video} />
        ))}
      </View>
      <Button
        title="Submit video URL"
        onPress={() => router.push(`/campaign/${campaign.id}/submit`)}
      />
    </AppScreen>
  );
}

const styles = StyleSheet.create({
