import { useEffect, useState } from 'react';
import { Image, StyleSheet, Text, View } from 'react-native';

interface BrandLogoProps {
  brandName: string;
  logoUrl?: string;
  size?: number;
}

const getInitials = (brandName: string) =>
  brandName
    .split(' ')
    .map((part) => part[0])
    .join('')
    .slice(0, 2)
    .toUpperCase();

export function BrandLogo({ brandName, logoUrl, size = 40 }: BrandLogoProps) {
  const [failed, setFailed] = useState(false);

  useEffect(() => {
    setFailed(false);
  }, [logoUrl]);

  return (
    <View style={[styles.logo, { width: size, height: size }]}>
      {logoUrl && !failed ? (
        <Image
          source={{ uri: logoUrl }}
          style={styles.image}
          resizeMode="contain"
          onError={() => setFailed(true)}
        />
      ) : (
        <Text style={[styles.initials, { fontSize: Math.max(12, size * 0.34) }]}>
          {getInitials(brandName)}
        </Text>
      )}
    </View>
  );
}

const styles = StyleSheet.create({
  logo: {
    alignItems: 'center',
    justifyContent: 'center',
    borderRadius: 8,
    overflow: 'hidden',
    backgroundColor: '#ffffff',
    borderWidth: 1,
    borderColor: '#e5e7eb',
  },
  image: {
    width: '100%',
    height: '100%',
  },
  initials: {
    color: '#111827',
    fontWeight: '700',
    letterSpacing: 0,
  },
});

